{
  "name": "Smart EMI & Amortization Planner",
  "description": "A comprehensive EMI calculator featuring dynamic interest rate changes, part-payment management (reduce tenure or EMI), and interactive amortization charts."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface LoanInput {
  principal: number;
  annualRate: number;
  tenureMonths: number;
}

export enum EventType {
  PART_PAYMENT = 'PART_PAYMENT',
  RATE_CHANGE = 'RATE_CHANGE',
}

export enum PartPaymentStrategy {
  REDUCE_EMI = 'REDUCE_EMI',
  REDUCE_TENURE = 'REDUCE_TENURE',
}

export interface LoanEvent {
  id: string;
  month: number; // 1-based index (e.g., Month 12)
  type: EventType;
  value: number; // Amount for payment, or New Rate % for rate change
  strategy?: PartPaymentStrategy; // Only for Part Payment
}

export interface ScheduleItem {
  month: number;
  openingBalance: number;
  emi: number;
  interestComponent: number;
  principalComponent: number;
  closingBalance: number;
  prepayment: number;
  rate: number; // The rate applied this month
}

export interface CalculationResult {
  schedule: ScheduleItem[];
  totalInterest: number;
  totalPayment: number;
  finalTenure: number; // Actual months taken to close
}

import { LoanInput, LoanEvent, ScheduleItem, CalculationResult, EventType, PartPaymentStrategy } from '../types';

export const calculatePMT = (principal: number, monthlyRate: number, months: number): number => {
  if (monthlyRate === 0) return principal / months;
  return (principal * monthlyRate * Math.pow(1 + monthlyRate, months)) / (Math.pow(1 + monthlyRate, months) - 1);
};

export const calculateAmortizationSchedule = (
  inputs: LoanInput,
  events: LoanEvent[]
): CalculationResult => {
  const schedule: ScheduleItem[] = [];
  let currentPrincipal = inputs.principal;
  let currentRate = inputs.annualRate;
  let currentMonthlyRate = currentRate / 12 / 100;

  // Sort events by month to process them in order
  const sortedEvents = [...events].sort((a, b) => a.month - b.month);

  // We need to determine the EMI dynamically.
  // Initially, we calculate the base EMI.
  let currentTenureRemaining = inputs.tenureMonths;
  let currentEMI = calculatePMT(currentPrincipal, currentMonthlyRate, currentTenureRemaining);

  let totalInterest = 0;
  let totalPrepayment = 0;

  // We loop until principal is zero or we reach a safety limit (to prevent infinite loops)
  const MAX_MONTHS = inputs.tenureMonths * 3; 
  let month = 1;

  while (currentPrincipal > 1 && month <= MAX_MONTHS) { // threshold > 1 to avoid floating point issues near 0
    // 1. Check for events occurring at the start of this month
    const monthEvents = sortedEvents.filter(e => e.month === month);
    let prepaymentThisMonth = 0;

    for (const event of monthEvents) {
      if (event.type === EventType.RATE_CHANGE) {
        currentRate = event.value;
        currentMonthlyRate = currentRate / 12 / 100;
        // Recalculate EMI based on new rate and remaining tenure (approx)
        // Note: For rate changes, banks usually keep tenure same and increase EMI, 
        // OR keep EMI same and increase tenure. Here we assume we recalculate EMI to fit remaining original tenure logic
        // unless specified otherwise. Standard practice: Recalculate EMI to finish in remaining original time (unless extended).
        // However, to keep it consistent with "Reduce EMI" vs "Reduce Tenure" logic generally:
        // A simple approach: Recalculate EMI required to clear balance in remaining scheduled months.
        const remainingMonthsIdeally = Math.max(1, inputs.tenureMonths - month + 1);

        // If we previously reduced tenure, our target remaining might be different. 
        // Let's stick to: Recalculate EMI to clear debt over currently projected remaining months.
        // Actually, easiest way: Recalculate EMI for remaining schedule.
        currentEMI = calculatePMT(currentPrincipal, currentMonthlyRate, currentTenureRemaining);
      } 
      else if (event.type === EventType.PART_PAYMENT) {
        const paymentAmount = event.value;
        prepaymentThisMonth += paymentAmount;
        currentPrincipal -= paymentAmount;
        totalPrepayment += paymentAmount;

        if (currentPrincipal <= 0) {
          currentPrincipal = 0;
          break; // Loop will handle exit
        }

        if (event.strategy === PartPaymentStrategy.REDUCE_EMI) {
           // Recalculate EMI for same remaining tenure
           currentEMI = calculatePMT(currentPrincipal, currentMonthlyRate, currentTenureRemaining);
        } else {
           // REDUCE_TENURE: Keep EMI same (do nothing to currentEMI), tenure will naturally shorten
           // Exception: If currentEMI is now > currentPrincipal + interest, it will finish next month.
        }
      }
    }

    if (currentPrincipal <= 0) {
       // Paid off by prepayment
       break;
    }

    const openingBalance = currentPrincipal;
    const interest = openingBalance * currentMonthlyRate;

    // Calculate Principal Component
    // If it's the last payment or EMI is huge, cap it.
    let principalComponent = currentEMI - interest;

    // Adjust for final month
    let paidEMI = currentEMI;

    if (openingBalance + interest <= currentEMI) {
        // Final payment
        paidEMI = openingBalance + interest;
        principalComponent = openingBalance;
    } else {
        // If principal component is negative (interest > EMI), we have a problem (negative amortization).
        // In a real app, we'd warn the user or force a higher EMI. 
        // Here, we'll let it grow but typically EMI > Interest.
    }

    const closingBalance = openingBalance - principalComponent;

    schedule.push({
      month,
      openingBalance,
      emi: paidEMI,
      interestComponent: interest,
      principalComponent,
      closingBalance: closingBalance < 0.1 ? 0 : closingBalance, // Round near zero
      prepayment: prepaymentThisMonth,
      rate: currentRate
    });

    totalInterest += interest;
    currentPrincipal = closingBalance;

    if (currentPrincipal < 0.1) currentPrincipal = 0; // Snap to zero

    month++;
    currentTenureRemaining--;
    if(currentTenureRemaining < 1) currentTenureRemaining = 1; // Safety for recalc
  }

  return {
    schedule,
    totalInterest,
    totalPayment: inputs.principal + totalInterest, // This is technically Principal + Interest. Actual cash flow includes prepayments.
    finalTenure: schedule.length
  };
};

export const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('en-IN', {
    style: 'currency',
    currency: 'INR', // Using INR as context implies EMI usually, but fits generic $ too if locale changed
    maximumFractionDigits: 0
  }).format(value);
};

import React from 'react';

interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  label: string;
  icon?: React.ReactNode;
  suffix?: string;
  error?: string;
}

export const Input: React.FC<InputProps> = ({ label, icon, suffix, error, className, ...props }) => {
  return (
    <div className={`w-full ${className || ''}`}>
      <label className="block text-sm font-medium text-gray-700 mb-1">
        {label}
      </label>
      <div className="relative rounded-md shadow-sm">
        {icon && (
          <div className="pointer-events-none absolute inset-y-0 left-0 flex items-center pl-3">
            <span className="text-gray-500 sm:text-sm">{icon}</span>
          </div>
        )}
        <input
          {...props}
          className={`block w-full rounded-md border-0 py-2.5 text-gray-900 ring-1 ring-inset ring-gray-300 placeholder:text-gray-400 focus:ring-2 focus:ring-inset focus:ring-primary sm:text-sm sm:leading-6 ${icon ? 'pl-10' : 'pl-3'} ${suffix ? 'pr-12' : 'pr-3'} transition-all`}
        />
        {suffix && (
          <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center pr-3">
            <span className="text-gray-500 sm:text-sm">{suffix}</span>
          </div>
        )}
      </div>
      {error && <p className="mt-1 text-xs text-red-500">{error}</p>}
    </div>
  );
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'danger';
  size?: 'sm' | 'md' | 'lg';
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  className, 
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center rounded-md font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 disabled:pointer-events-none";

  const variants = {
    primary: "bg-primary text-white hover:bg-indigo-700 focus:ring-primary shadow-sm",
    secondary: "bg-secondary text-white hover:bg-emerald-600 focus:ring-secondary shadow-sm",
    outline: "border border-gray-300 bg-white text-gray-700 hover:bg-gray-50 focus:ring-primary",
    danger: "bg-red-600 text-white hover:bg-red-700 focus:ring-red-500 shadow-sm"
  };

  const sizes = {
    sm: "h-8 px-3 text-xs",
    md: "h-10 px-4 py-2 text-sm",
    lg: "h-12 px-6 text-base"
  };

  return (
    <button
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className || ''}`}
      {...props}
    >
      {children}
    </button>
  );
};

import React, { useState } from 'react';
import { Plus, Trash2, DollarSign, Percent, Calendar } from 'lucide-react';
import { LoanEvent, EventType, PartPaymentStrategy } from '../types';
import { Button } from './ui/Button';
import { Input } from './ui/Input';

interface EventSectionProps {
  events: LoanEvent[];
  onAddEvent: (event: LoanEvent) => void;
  onRemoveEvent: (id: string) => void;
  maxMonths: number;
}

export const EventSection: React.FC<EventSectionProps> = ({ events, onAddEvent, onRemoveEvent, maxMonths }) => {
  const [eventType, setEventType] = useState<EventType>(EventType.PART_PAYMENT);
  const [month, setMonth] = useState<number>(12);
  const [value, setValue] = useState<number>(10000);
  const [strategy, setStrategy] = useState<PartPaymentStrategy>(PartPaymentStrategy.REDUCE_TENURE);

  const handleAdd = () => {
    if (month < 1 || month > maxMonths) return;
    if (value <= 0) return;

    const newEvent: LoanEvent = {
      id: Math.random().toString(36).substr(2, 9),
      month,
      type: eventType,
      value: Number(value),
      strategy: eventType === EventType.PART_PAYMENT ? strategy : undefined
    };
    onAddEvent(newEvent);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6">
      <h3 className="text-lg font-semibold text-gray-900 mb-4 flex items-center gap-2">
        <span className="bg-accent/10 text-accent p-1.5 rounded-lg">
          <Calendar size={18} />
        </span>
        Advanced Options
      </h3>

      <div className="space-y-4">
        {/* Type Selection */}
        <div className="flex rounded-md shadow-sm" role="group">
          <button
            type="button"
            onClick={() => setEventType(EventType.PART_PAYMENT)}
            className={`flex-1 px-4 py-2 text-sm font-medium border rounded-l-lg ${
              eventType === EventType.PART_PAYMENT 
                ? 'bg-secondary/10 text-secondary border-secondary' 
                : 'bg-white text-gray-700 border-gray-200 hover:bg-gray-50'
            }`}
          >
            Part Payment
          </button>
          <button
            type="button"
            onClick={() => setEventType(EventType.RATE_CHANGE)}
            className={`flex-1 px-4 py-2 text-sm font-medium border-t border-b border-r rounded-r-lg ${
              eventType === EventType.RATE_CHANGE 
                ? 'bg-accent/10 text-accent border-accent' 
                : 'bg-white text-gray-700 border-gray-200 hover:bg-gray-50'
            }`}
          >
            Rate Change
          </button>
        </div>

        {/* Inputs */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <Input 
            label="After Month" 
            type="number" 
            min={1} 
            max={maxMonths}
            value={month}
            onChange={(e) => setMonth(Number(e.target.value))}
            suffix="th Month"
          />

          <Input 
            label={eventType === EventType.PART_PAYMENT ? "Amount" : "New Interest Rate"}
            type="number"
            min={0}
            step={eventType === EventType.RATE_CHANGE ? 0.1 : 1000}
            value={value}
            onChange={(e) => setValue(Number(e.target.value))}
            icon={eventType === EventType.PART_PAYMENT ? <DollarSign size={14} /> : undefined}
            suffix={eventType === EventType.RATE_CHANGE ? "%" : undefined}
          />
        </div>

        {eventType === EventType.PART_PAYMENT && (
          <div className="p-3 bg-gray-50 rounded-lg space-y-2">
            <span className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Effect</span>
            <div className="flex gap-4">
              <label className="flex items-center gap-2 cursor-pointer">
                <input 
                  type="radio" 
                  name="strategy" 
                  checked={strategy === PartPaymentStrategy.REDUCE_TENURE}
                  onChange={() => setStrategy(PartPaymentStrategy.REDUCE_TENURE)}
                  className="text-primary focus:ring-primary"
                />
                <span className="text-sm text-gray-700">Reduce Tenure</span>
              </label>
              <label className="flex items-center gap-2 cursor-pointer">
                <input 
                  type="radio" 
                  name="strategy" 
                  checked={strategy === PartPaymentStrategy.REDUCE_EMI}
                  onChange={() => setStrategy(PartPaymentStrategy.REDUCE_EMI)}
                  className="text-primary focus:ring-primary"
                />
                <span className="text-sm text-gray-700">Reduce EMI</span>
              </label>
            </div>
          </div>
        )}

        <Button onClick={handleAdd} className="w-full" icon={<Plus size={18} />}>
          Add Event
        </Button>
      </div>

      {/* Event List */}
      {events.length > 0 && (
        <div className="mt-6 border-t pt-4">
          <h4 className="text-sm font-medium text-gray-500 mb-3">Scheduled Events</h4>
          <div className="space-y-2 max-h-60 overflow-y-auto custom-scrollbar pr-1">
            {events.map((event) => (
              <div key={event.id} className="flex items-center justify-between p-3 bg-white border border-gray-100 rounded-lg shadow-sm text-sm">
                <div className="flex items-center gap-3">
                  <div className={`p-2 rounded-full ${event.type === EventType.PART_PAYMENT ? 'bg-green-100 text-green-600' : 'bg-amber-100 text-amber-600'}`}>
                    {event.type === EventType.PART_PAYMENT ? <DollarSign size={14} /> : <Percent size={14} />}
                  </div>
                  <div>
                    <p className="font-medium text-gray-900">
                      Month {event.month}: {event.type === EventType.PART_PAYMENT ? 'Part Payment' : 'Rate Change'}
                    </p>
                    <p className="text-xs text-gray-500">
                      {event.type === EventType.PART_PAYMENT 
                        ? `${event.value.toLocaleString()} (${event.strategy === PartPaymentStrategy.REDUCE_EMI ? 'Reduce EMI' : 'Reduce Tenure'})` 
                        : `New Rate: ${event.value}%`}
                    </p>
                  </div>
                </div>
                <button 
                  onClick={() => onRemoveEvent(event.id)}
                  className="text-gray-400 hover:text-red-500 transition-colors p-1"
                >
                  <Trash2 size={16} />
                </button>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

import React from 'react';
import { formatCurrency } from '../utils/calculations';
import { CalendarClock, Coins, Wallet } from 'lucide-react';

interface SummaryCardsProps {
  totalInterest: number;
  totalPayment: number;
  monthlyEMI: number;
  finalTenure: number;
  originalTenure: number;
}

export const SummaryCards: React.FC<SummaryCardsProps> = ({ 
  totalInterest, 
  totalPayment, 
  monthlyEMI,
  finalTenure,
  originalTenure
}) => {
  const tenureSaved = originalTenure - finalTenure;

  return (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
      {/* Monthly EMI */}
      <div className="bg-gradient-to-br from-primary to-indigo-700 rounded-xl p-6 text-white shadow-lg shadow-indigo-200">
        <div className="flex items-start justify-between">
          <div>
            <p className="text-indigo-100 text-sm font-medium mb-1">Current EMI</p>
            <h3 className="text-3xl font-bold tracking-tight">{formatCurrency(monthlyEMI)}</h3>
            <p className="text-xs text-indigo-200 mt-2 opacity-80">Monthly Instalment</p>
          </div>
          <div className="p-3 bg-white/10 rounded-lg backdrop-blur-sm">
            <Wallet size={24} className="text-white" />
          </div>
        </div>
      </div>

      {/* Total Interest */}
      <div className="bg-white rounded-xl p-6 border border-gray-100 shadow-sm">
        <div className="flex items-start justify-between">
          <div>
            <p className="text-gray-500 text-sm font-medium mb-1">Total Interest</p>
            <h3 className="text-2xl font-bold text-gray-900">{formatCurrency(totalInterest)}</h3>
            <p className="text-xs text-gray-400 mt-2">
              {(totalInterest / (totalPayment - totalInterest || 1) * 100).toFixed(1)}% of Principal
            </p>
          </div>
          <div className="p-3 bg-orange-50 rounded-lg text-orange-500">
            <Coins size={24} />
          </div>
        </div>
      </div>

      {/* Tenure Info */}
      <div className="bg-white rounded-xl p-6 border border-gray-100 shadow-sm">
        <div className="flex items-start justify-between">
          <div>
            <p className="text-gray-500 text-sm font-medium mb-1">Duration</p>
            <h3 className="text-2xl font-bold text-gray-900">{finalTenure} <span className="text-sm font-normal text-gray-500">Months</span></h3>
            {tenureSaved > 0 ? (
               <p className="text-xs text-green-600 font-semibold mt-2">Saved {tenureSaved} months!</p>
            ) : (
               <p className="text-xs text-gray-400 mt-2">Full tenure</p>
            )}
          </div>
          <div className="p-3 bg-blue-50 rounded-lg text-blue-500">
            <CalendarClock size={24} />
          </div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, BarChart, Bar, Legend, PieChart, Pie, Cell } from 'recharts';
import { ScheduleItem } from '../types';

interface AmortizationChartProps {
  data: ScheduleItem[];
  principal: number;
  totalInterest: number;
}

export const AmortizationChart: React.FC<AmortizationChartProps> = ({ data, principal, totalInterest }) => {
  const pieData = [
    { name: 'Principal', value: principal },
    { name: 'Total Interest', value: totalInterest },
  ];
  const COLORS = ['#4F46E5', '#F59E0B'];

  // Sample data to improve performance if array is huge, though < 360 points is usually fine.
  const chartData = data; 

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
      {/* Balance Over Time */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 lg:col-span-2">
        <h3 className="text-lg font-semibold text-gray-800 mb-6">Amortization Curve</h3>
        <div className="h-72 w-full">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart
              data={chartData}
              margin={{ top: 10, right: 30, left: 0, bottom: 0 }}
            >
              <defs>
                <linearGradient id="colorBalance" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#4F46E5" stopOpacity={0.1}/>
                  <stop offset="95%" stopColor="#4F46E5" stopOpacity={0}/>
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#E2E8F0" />
              <XAxis 
                dataKey="month" 
                tick={{fill: '#94A3B8', fontSize: 12}} 
                tickLine={false}
                axisLine={false}
              />
              <YAxis 
                tick={{fill: '#94A3B8', fontSize: 12}} 
                tickFormatter={(val) => `₹${(val/1000).toFixed(0)}k`}
                tickLine={false}
                axisLine={false}
              />
              <Tooltip 
                contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                formatter={(value: number) => Math.round(value).toLocaleString()}
              />
              <Area 
                type="monotone" 
                dataKey="closingBalance" 
                stroke="#4F46E5" 
                strokeWidth={3}
                fillOpacity={1} 
                fill="url(#colorBalance)" 
                name="Outstanding Balance"
              />
            </AreaChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Breakup Pie Chart */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
        <h3 className="text-lg font-semibold text-gray-800 mb-2">Total Breakup</h3>
        <div className="h-64 w-full relative">
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={pieData}
                cx="50%"
                cy="50%"
                innerRadius={60}
                outerRadius={80}
                fill="#8884d8"
                paddingAngle={5}
                dataKey="value"
              >
                {pieData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip formatter={(val: number) => `₹${val.toLocaleString()}`} />
              <Legend verticalAlign="bottom" height={36}/>
            </PieChart>
          </ResponsiveContainer>
          {/* Center Text */}
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none pb-8">
            <div className="text-center">
              <span className="text-xs text-gray-500 block">Total Payable</span>
              <span className="text-sm font-bold text-gray-800">
                {((principal + totalInterest)/1000).toFixed(1)}k
              </span>
            </div>
          </div>
        </div>
      </div>

       {/* Components Bar Chart */}
       <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 lg:col-span-3">
        <h3 className="text-lg font-semibold text-gray-800 mb-6">Principal vs Interest Component</h3>
        <div className="h-64 w-full">
           <ResponsiveContainer width="100%" height="100%">
            <BarChart
              data={chartData}
              margin={{ top: 20, right: 30, left: 20, bottom: 5 }}
            >
              <CartesianGrid strokeDasharray="3 3" vertical={false} />
              <XAxis dataKey="month" tickLine={false} axisLine={false} tick={{fontSize: 12}} />
              <YAxis tickLine={false} axisLine={false} tick={{fontSize: 12}} />
              <Tooltip cursor={{fill: 'transparent'}} />
              <Legend />
              <Bar dataKey="principalComponent" stackId="a" fill="#10B981" name="Principal" radius={[0, 0, 4, 4]} />
              <Bar dataKey="interestComponent" stackId="a" fill="#F59E0B" name="Interest" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { ScheduleItem } from '../types';

interface AmortizationTableProps {
  schedule: ScheduleItem[];
}

export const AmortizationTable: React.FC<AmortizationTableProps> = ({ schedule }) => {
  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
      <div className="p-6 border-b border-gray-100">
        <h3 className="text-lg font-semibold text-gray-800">Amortization Schedule</h3>
      </div>
      <div className="overflow-x-auto custom-scrollbar">
        <table className="min-w-full divide-y divide-gray-200">
          <thead className="bg-gray-50">
            <tr>
              <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Month</th>
              <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Opening</th>
              <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">EMI</th>
              <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Principal</th>
              <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Interest</th>
              <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Extra Paid</th>
              <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Closing</th>
